package com.treeeducation.ioas.task;
import jakarta.persistence.*;import java.time.Instant;
/** Cross-module task linked to packages, assets and optionally leads. */
@Entity @Table(name="ioas_task") public class Task{ @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Enumerated(EnumType.STRING) @Column(nullable=false,length=20) private TaskType type; @Enumerated(EnumType.STRING) @Column(nullable=false,length=30) private TaskStatus status=TaskStatus.pending; @Column(nullable=false,length=160) private String title; private Long packageId; private Long assetFileId; private Long leadId; private Long assigneeId; @Column(nullable=false) private Instant createdAt=Instant.now(); private Instant updatedAt=Instant.now(); public Long getId(){return id;} public void setId(Long id){this.id=id;} public TaskType getType(){return type;} public void setType(TaskType type){this.type=type;} public TaskStatus getStatus(){return status;} public void setStatus(TaskStatus status){this.status=status;} public String getTitle(){return title;} public void setTitle(String title){this.title=title;} public Long getPackageId(){return packageId;} public void setPackageId(Long packageId){this.packageId=packageId;} public Long getAssetFileId(){return assetFileId;} public void setAssetFileId(Long assetFileId){this.assetFileId=assetFileId;} public Long getLeadId(){return leadId;} public void setLeadId(Long leadId){this.leadId=leadId;} public Long getAssigneeId(){return assigneeId;} public void setAssigneeId(Long assigneeId){this.assigneeId=assigneeId;} public Instant getCreatedAt(){return createdAt;} public void setCreatedAt(Instant createdAt){this.createdAt=createdAt;} public Instant getUpdatedAt(){return updatedAt;} public void setUpdatedAt(Instant updatedAt){this.updatedAt=updatedAt;} }
